"""Generated by w2a — entrypoint for "Support Ticket Triage and Reporting" (scheduled_watcher).

Trigger: A new ticket arrives in Zendesk.
"""

from __future__ import annotations

import argparse
import sys
import time
from pathlib import Path

from crew import run_once, task_classify_ticket, task_generate_weekly_report, task_trigger_alert

_TASK_IDS = ['classify_ticket', 'generate_weekly_report', 'trigger_alert', ]
_TASK_VARS = {
    'classify_ticket': task_classify_ticket,
    'generate_weekly_report': task_generate_weekly_report,
    'trigger_alert': task_trigger_alert,
}


def _log(event: str, task_id: str) -> None:
    print(f"[w2a] {event} task={task_id}", flush=True)


def _wire_callbacks() -> None:
    for task_id, task in _TASK_VARS.items():
        task.callback = lambda output, _id=task_id: _log("TASK_END", _id)


def _read_input(source: str) -> str:
    if source == "-":
        return sys.stdin.read()
    return Path(source).read_text(encoding="utf-8")


def main() -> int:
    parser = argparse.ArgumentParser(description='Categorize incoming Zendesk support tickets, alert on-call staff for urgent issues, and generate a weekly analytical summary.')
    parser.add_argument("input", nargs="?", default="-", help="Input file, or '-' for stdin.")
    parser.add_argument("--once", action="store_true", help="Run a single poll pass and exit.")
    parser.add_argument("--interval", type=float, default=60.0, help="Seconds between polls.")
    args = parser.parse_args()

    payload = _read_input(args.input)
    _wire_callbacks()

    while True:
        for task_id in _TASK_IDS:
            _log("TASK_START", task_id)
        result = run_once(inputs={"input": payload})
        print("\n--- RESULT ---")
        print(result.raw)
        if args.once:
            return 0
        time.sleep(args.interval)


if __name__ == "__main__":
    raise SystemExit(main())
